package org.apache.kafka.streams.processor.internals;

import org.apache.kafka.common.internals.KafkaFutureImpl;
import org.apache.kafka.common.serialization.Serdes;
import org.apache.kafka.streams.StreamsConfig;
import org.apache.kafka.streams.TopologyConfig;
import org.apache.kafka.streams.processor.TaskId;

import java.util.Properties;
import java.util.concurrent.ConcurrentNavigableMap;
import java.util.concurrent.ConcurrentSkipListMap;
import java.util.concurrent.locks.ReentrantLock;

/**
 * Fray test for TopologyMetadata deadlock with DefaultTaskManager.
 *
 * Before the fix, isTaskTopologyStale() acquired topologyLock. Combined with
 * a lifecycle observer that acquires tasksLock (as DefaultTaskManager does),
 * this created a deadlock cycle:
 *   Thread 1: tasksLock → topologyLock (via isTaskTopologyStale)
 *   Thread 2: topologyLock → tasksLock (via lifecycle observer)
 *
 * After the fix, isTaskTopologyStale() no longer acquires topologyLock since
 * builders is a ConcurrentSkipListMap with thread-safe reads.
 */
public class TopologyMetadataDeadlockTest {

    public static void main(final String[] args) throws Exception {
        final Properties props = new Properties();
        props.put(StreamsConfig.APPLICATION_ID_CONFIG, "test-app");
        props.put(StreamsConfig.BOOTSTRAP_SERVERS_CONFIG, "localhost:9092");
        props.put(StreamsConfig.DEFAULT_KEY_SERDE_CLASS_CONFIG, Serdes.StringSerde.class.getName());
        props.put(StreamsConfig.DEFAULT_VALUE_SERDE_CLASS_CONFIG, Serdes.StringSerde.class.getName());
        final StreamsConfig config = new StreamsConfig(props);

        // Create a named topology builder for the initial topology
        final TopologyConfig topoConfig1 = new TopologyConfig("topo-1", config, new Properties());
        final InternalTopologyBuilder builder1 = new InternalTopologyBuilder(topoConfig1);
        builder1.addSource(null, "source-1", null, null, null, "topic-1");

        // Create TopologyMetadata with the initial named topology
        final ConcurrentNavigableMap<String, InternalTopologyBuilder> builders = new ConcurrentSkipListMap<>();
        builders.put("topo-1", builder1);
        final TopologyMetadata topologyMetadata = new TopologyMetadata(builders, config);

        // Simulate tasksLock (as in DefaultTaskManager)
        final ReentrantLock tasksLock = new ReentrantLock();

        // Register lifecycle observer that acquires tasksLock (like DefaultTaskManager.validateTopologyConsistency)
        topologyMetadata.registerLifecycleObserver((newVersion, activeTopologies) -> {
            tasksLock.lock();
            try {
                // Simulate work under tasksLock
            } finally {
                tasksLock.unlock();
            }
        });

        // Create a new topology builder for registration
        final TopologyConfig topoConfig2 = new TopologyConfig("topo-2", config, new Properties());
        final InternalTopologyBuilder builder2 = new InternalTopologyBuilder(topoConfig2);
        builder2.addSource(null, "source-2", null, null, null, "topic-2");

        final TaskId taskId = new TaskId(0, 0, "topo-1");

        // Thread 1: tasksLock → isTaskTopologyStale (before fix: acquires topologyLock)
        final Thread t1 = new Thread(() -> {
            for (int i = 0; i < 5; i++) {
                tasksLock.lock();
                try {
                    topologyMetadata.isTaskTopologyStale(taskId);
                } finally {
                    tasksLock.unlock();
                }
            }
        });

        // Thread 2: registerAndBuildNewTopology → topologyLock → notifyObservers → tasksLock
        final Thread t2 = new Thread(() -> {
            final KafkaFutureImpl<Void> future = new KafkaFutureImpl<>();
            topologyMetadata.registerAndBuildNewTopology(future, builder2);
        });

        t1.start();
        t2.start();
        t1.join();
        t2.join();
    }
}

